import{_ as e,o as r,c as h,a2 as l}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 新手常見問題 FAQ：你問我答","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/faq.md","filePath":"bannerlord/faq.md"}'),t={name:"bannerlord/faq.md"};function i(o,a,n,d,q,s){return r(),h("div",null,[...a[0]||(a[0]=[l('<h1 id="騎砍2-新手常見問題-faq-你問我答" tabindex="-1">騎砍2 | 新手常見問題 FAQ：你問我答 <a class="header-anchor" href="#騎砍2-新手常見問題-faq-你問我答" aria-label="Permalink to &quot;騎砍2 | 新手常見問題 FAQ：你問我答&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>有些問題大到可以寫一整篇攻略，有些小到一句話就能回答。這篇收集新手最常問的問題，快速解答。</p><hr><h2 id="q1-我剛進遊戲-該做什麼" tabindex="-1">Q1：我剛進遊戲，該做什麼？ <a class="header-anchor" href="#q1-我剛進遊戲-該做什麼" aria-label="Permalink to &quot;Q1：我剛進遊戲，該做什麼？&quot;">​</a></h2><p>去競技場打練習賽 → 賺錢 → 招 15 個帝國新兵 → 打劫匪 → 存到 10000 金 → 當傭兵。</p><hr><h2 id="q2-為什麼我的兵一直跑掉" tabindex="-1">Q2：為什麼我的兵一直跑掉？ <a class="header-anchor" href="#q2-為什麼我的兵一直跑掉" aria-label="Permalink to &quot;Q2：為什麼我的兵一直跑掉？&quot;">​</a></h2><p>因為你沒錢付薪水。打開隊伍介面看每日薪資，確保你的錢夠養兵至少 7 天。</p><hr><h2 id="q3-怎麼賺錢最快" tabindex="-1">Q3：怎麼賺錢最快？ <a class="header-anchor" href="#q3-怎麼賺錢最快" aria-label="Permalink to &quot;Q3：怎麼賺錢最快？&quot;">​</a></h2><p>前期競技場，中期跑商+工廠，後期鍛造。詳見 <a href="./money-making.html">賺錢密技</a>。</p><hr><h2 id="q4-哪個兵種最強" tabindex="-1">Q4：哪個兵種最強？ <a class="header-anchor" href="#q4-哪個兵種最強" aria-label="Permalink to &quot;Q4：哪個兵種最強？&quot;">​</a></h2><p>看情況。野戰最強是庫塞特可汗親衛（弓騎），攻城最強是斯特吉亞重裝斧兵，最萬用的是帝國軍團步兵。</p><hr><h2 id="q5-什麼時候可以攻城" tabindex="-1">Q5：什麼時候可以攻城？ <a class="header-anchor" href="#q5-什麼時候可以攻城" aria-label="Permalink to &quot;Q5：什麼時候可以攻城？&quot;">​</a></h2><p>至少 100+ 精兵，食物夠 7-14 天，確認附近沒有敵方援軍。不要從帝國內陸大城開始。</p><hr><h2 id="q6-俘虜能做什麼" tabindex="-1">Q6：俘虜能做什麼？ <a class="header-anchor" href="#q6-俘虜能做什麼" aria-label="Permalink to &quot;Q6：俘虜能做什麼？&quot;">​</a></h2><p>賣給酒館的贖金經紀人（普通幾十金，高級幾百金）。領主俘虜可以勒索贖金（幾萬到十幾萬）。</p><hr><h2 id="q7-怎麼結婚" tabindex="-1">Q7：怎麼結婚？ <a class="header-anchor" href="#q7-怎麼結婚" aria-label="Permalink to &quot;Q7：怎麼結婚？&quot;">​</a></h2><p>找未婚貴族 → 聊天選浪漫選項 → 玩說服小遊戲 → 跟對方族長談判付錢。</p><hr><h2 id="q8-我的角色會老死嗎" tabindex="-1">Q8：我的角色會老死嗎？ <a class="header-anchor" href="#q8-我的角色會老死嗎" aria-label="Permalink to &quot;Q8：我的角色會老死嗎？&quot;">​</a></h2><p>會。年齡到了屬性會下降，最終可能老死。你需要結婚生子培養接班人。</p><hr><h2 id="q9-裝-mod-會鎖成就嗎" tabindex="-1">Q9：裝 MOD 會鎖成就嗎？ <a class="header-anchor" href="#q9-裝-mod-會鎖成就嗎" aria-label="Permalink to &quot;Q9：裝 MOD 會鎖成就嗎？&quot;">​</a></h2><p>會。用 Achievement Unblocker MOD 可以解除限制。</p><hr><h2 id="q10-遊戲崩潰了怎麼辦" tabindex="-1">Q10：遊戲崩潰了怎麼辦？ <a class="header-anchor" href="#q10-遊戲崩潰了怎麼辦" aria-label="Permalink to &quot;Q10：遊戲崩潰了怎麼辦？&quot;">​</a></h2><ol><li>檢查 MOD 版本和排序</li><li>逐一關 MOD 排查</li><li>Steam → 驗證遊戲檔案完整性</li><li>更新顯示卡驅動</li></ol><hr><h2 id="q11-可以同時跟多個國家打仗嗎" tabindex="-1">Q11：可以同時跟多個國家打仗嗎？ <a class="header-anchor" href="#q11-可以同時跟多個國家打仗嗎" aria-label="Permalink to &quot;Q11：可以同時跟多個國家打仗嗎？&quot;">​</a></h2><p>不要。一次只打一國。雙線作戰 = 被夾攻 = 滅國。</p><hr><h2 id="q12-騎砍1跟騎砍2哪個好玩" tabindex="-1">Q12：騎砍1跟騎砍2哪個好玩？ <a class="header-anchor" href="#q12-騎砍1跟騎砍2哪個好玩" aria-label="Permalink to &quot;Q12：騎砍1跟騎砍2哪個好玩？&quot;">​</a></h2><p>騎砍2畫面更好、系統更深、MOD 生態持續成長。騎砍1 MOD 最多（但畫面老舊）。2026 年建議直接玩騎砍2。</p><hr><h2 id="還有問題" tabindex="-1">還有問題？ <a class="header-anchor" href="#還有問題" aria-label="Permalink to &quot;還有問題？&quot;">​</a></h2><p><a href="/feedback.html">回報給我們</a> → 我們會加到這篇 FAQ 裡。</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./beginner-guide.html">騎砍2 | 新手求生指南</a></li><li><a href="./">所有攻略總覽</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',51)])])}const b=e(t,[["render",i]]);export{u as __pageData,b as default};
